6570         Op2Info, Operands, I, TLI);
6571   }
6572   case Instruction::FNeg: {
6573     return TTI.getArithmeticInstrCost(
6574         I->getOpcode(), VectorTy, CostKind,
6575         {TargetTransformInfo::OK_AnyValue, TargetTransformInfo::OP_None},
6576         {TargetTransformInfo::OK_AnyValue, TargetTransformInfo::OP_None},
6577         I->getOperand(0), I);
6578   }
