6587                         match(I, m_LogicalOr(m_Value(Op0), m_Value(Op1))))) {
6588       // select x, y, false --> x & y
6589       // select x, true, y --> x | y
6590       const auto [Op1VK, Op1VP] = TTI::getOperandInfo(Op0);
6591       const auto [Op2VK, Op2VP] = TTI::getOperandInfo(Op1);
6592       assert(Op0->getType()->getScalarSizeInBits() == 1 &&
6593               Op1->getType()->getScalarSizeInBits() == 1);
