6663     auto ComputeCCH = [&](Instruction *I) -> TTI::CastContextHint {
6664       assert((isa<LoadInst>(I) || isa<StoreInst>(I)) &&
6665              "Expected a load or a store!");
6666 
6667       if (VF.isScalar() || !TheLoop->contains(I))
6668         return TTI::CastContextHint::Normal;
6669 
6670       switch (getWideningDecision(I, VF)) {
6671       case LoopVectorizationCostModel::CM_GatherScatter:
6672         return TTI::CastContextHint::GatherScatter;
6673       case LoopVectorizationCostModel::CM_Interleave:
6674         return TTI::CastContextHint::Interleave;
6675       case LoopVectorizationCostModel::CM_Scalarize:
6676       case LoopVectorizationCostModel::CM_Widen:
6677         return Legal->isMaskRequired(I) ? TTI::CastContextHint::Masked
6678                                         : TTI::CastContextHint::Normal;
6679       case LoopVectorizationCostModel::CM_Widen_Reverse:
6680         return TTI::CastContextHint::Reversed;
6681       case LoopVectorizationCostModel::CM_Unknown:
6682         llvm_unreachable("Instr did not go through cost modelling?");
6683       case LoopVectorizationCostModel::CM_VectorCall:
6684       case LoopVectorizationCostModel::CM_IntrinsicCall:
6685         llvm_unreachable_internal("Instr has invalid widening decision");
6686       }
6687 
6688       llvm_unreachable("Unhandled case!");
6689     };
6690 
6691     unsigned Opcode = I->getOpcode();
6692     TTI::CastContextHint CCH = TTI::CastContextHint::None;
6693     // For Trunc, the context is the only user, which must be a StoreInst.
6694     if (Opcode == Instruction::Trunc || Opcode == Instruction::FPTrunc) {
6695       if (I->hasOneUse())
6696         if (StoreInst *Store = dyn_cast<StoreInst>(*I->user_begin()))
6697           CCH = ComputeCCH(Store);
6698     }
6699     // For Z/Sext, the context is the operand, which must be a LoadInst.
6700     else if (Opcode == Instruction::ZExt || Opcode == Instruction::SExt ||
6701              Opcode == Instruction::FPExt) {
6702       if (LoadInst *Load = dyn_cast<LoadInst>(I->getOperand(0)))
6703         CCH = ComputeCCH(Load);
6704     }
6705 
6706     // We optimize the truncation of induction variables having constant
6707     // integer steps. The cost of these truncations is the same as the scalar
6708     // operation.
6709     if (isOptimizableIVTruncate(I, VF)) {
6710       auto *Trunc = cast<TruncInst>(I);
6711       return TTI.getCastInstrCost(Instruction::Trunc, Trunc->getDestTy(),
6712                                   Trunc->getSrcTy(), CCH, CostKind, Trunc);
6713     }
6714 
6715     // Detect reduction patterns
6716     if (auto RedCost = getReductionPatternCost(I, VF, VectorTy, CostKind))
6717       return *RedCost;
6718 
6719     Type *SrcScalarTy = I->getOperand(0)->getType();
6720     Instruction *Op0AsInstruction = dyn_cast<Instruction>(I->getOperand(0));
6721     if (canTruncateToMinimalBitwidth(Op0AsInstruction, VF))
6722       SrcScalarTy =
6723           IntegerType::get(SrcScalarTy->getContext(), MinBWs[Op0AsInstruction]);
6724     Type *SrcVecTy =
6725         VectorTy->isVectorTy() ? ToVectorTy(SrcScalarTy, VF) : SrcScalarTy;
6726 
6727     if (canTruncateToMinimalBitwidth(I, VF)) {
6728       // If the result type is <= the source type, there will be no extend
6729       // after truncating the users to the minimal required bitwidth.
6730       if (VectorTy->getScalarSizeInBits() <= SrcVecTy->getScalarSizeInBits() &&
6731           (I->getOpcode() == Instruction::ZExt ||
6732            I->getOpcode() == Instruction::SExt))
6733         return 0;
6734     }
6735 
6736     return TTI.getCastInstrCost(Opcode, VectorTy, SrcVecTy, CCH, CostKind, I);
6737   }
6738   case Instruction::Call:
6739     return getVectorCallCost(cast<CallInst>(I), VF);
6740   case Instruction::ExtractValue:
6741     return TTI.getInstructionCost(I, TTI::TCK_RecipThroughput);
6742   case Instruction::Alloca:
6743     // We cannot easily widen alloca to a scalable alloca, as
6744     // the result would need to be a vector of pointers.
6745     if (VF.isScalable())
6746       return InstructionCost::getInvalid();
6747     [[fallthrough]];
6748   default:
6749     // This opcode is unknown. Assume that it is the same as 'mul'.
6750     return TTI.getArithmeticInstrCost(Instruction::Mul, VectorTy, CostKind);
6751   } // end of switch.
